#include<cstdio>
#include<vector>
#include<algorithm>
#include<assert.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
#define grep(b,c) for(int c(head[b]);c;c=nxt[c])
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int B=400;typedef long long ll;
template<typename T> inline void CV(vector<T> &v){vector<T> t;v.swap(t);}
inline vector<ll> NV(){vector<ll> t;return t;}
const int N=1e5+10;
struct Vec
{
	vector<vector<ll>> a;
	inline Vec(){a.push_back(NV());a[0].push_back(1ll<<62);}
	inline void Ins(ll x){a[0].push_back(x);}
	inline void rebuild()
	{
		sort(a[0].begin(),a[0].end());int tmp=a[0].size();
		for(int i=1;i*(B/2)<tmp;++i)
		{
			a.push_back(NV());int lm=min((i+1)*(B/2),tmp); 
			for(int j=i*(B/2);j<lm;++j)a[i].push_back(a[0][j]);
		}
		if(tmp>=(B/2))a[0].erase(a[0].begin()+(B/2),a[0].end());
	}
	inline int qry(ll x)
	{
		int sum=0;
		for(unsigned i=0;i<a.size();++i)
		{
			if(*prev(a[i].end())>x)
			{
				int l=0,r=a[i].size()-1,mid;
				while(l<=r)a[i][mid=(l+r)>>1]<=x?l=mid+1:r=mid-1;sum+=l;
				return sum;
			}
			sum+=a[i].size();
		}
		return sum;
	}
	inline void ins(ll x)
	{
		for(unsigned i=0;i<a.size();++i)
		{
			if(*prev(a[i].end())>=x)
			{
				int l=0,r=a[i].size()-1,mid;
				while(l<=r)a[i][mid=(l+r)>>1]<=x?l=mid+1:r=mid-1;
				a[i].insert(a[i].begin()+l,x);
				if(a[i].size()==B)
				{
					a.insert(a.begin()+i+1,NV());
					for(unsigned j=B/2;j<a[i].size();++j)a[i+1].push_back(a[i][j]);
					a[i].erase(a[i].begin()+B/2,a[i].end());
				}
				return;
			}
		}
	}
	inline void clear(){vector<vector<ll>> t(1);a.swap(t);a[0].push_back(1ll<<62);}
}ToFa[N],ToMe[N];
const double alpha=0.8;const int M=1e9;
vector<int> son[N],anc[N];vector<ll> d[N];int n;ll ans;
int head[N],val[N<<1],des[N<<1],nxt[N<<1],cgt;
inline void ins(int x,int y,int z)
{
	nxt[++cgt]=head[x];des[head[x]=cgt]=y;val[cgt]=z;
	nxt[++cgt]=head[y];des[head[y]=cgt]=x;val[cgt]=z;
}
int siz[N];ll dis[N];int R[N];bool vis[N];
int Mn,Rt,Sz;inline void getRt(int u,int fa=0)
{
	siz[u]=1;int mx=0;
	grep(u,i)if(!vis[des[i]]&&des[i]!=fa)
	{
		int v=des[i];getRt(v,u);
		siz[u]+=siz[v];
		mx=max(mx,siz[v]);
	}
	mx=max(mx,Sz-siz[u]);mx<Mn?Mn=mx,Rt=u:0;
}
int RT;inline void getSz(int u,int fa=0)
{
	siz[u]=1;if(!fa)dis[u]=0;
	son[RT].push_back(u);
	anc[u].push_back(RT);
	if(anc[RT].size()>1)ToFa[RT].Ins(*prev(d[u].end())-R[u]);
	ToMe[RT].Ins(dis[u]-R[u]);
	d[u].push_back(dis[u]);
//	if(u==13)puts("cnmlgb");
	grep(u,i)if(!vis[des[i]]&&des[i]!=fa)
	{
		int v=des[i];dis[v]=dis[u]+val[i];
		getSz(v,u);siz[u]+=siz[v];
	}
}
inline void build(int u)
{
	vis[u]=true;CV(son[u]);getSz(RT=u);
	ToMe[u].rebuild();if(anc[u].size()!=1)ToFa[u].rebuild();
	grep(u,i)if(!vis[des[i]]){int v=des[i];Sz=siz[v];Mn=M;getRt(v);build(Rt);}
}
int main()
{
//	FIN("P3920_5.in");
	read();n=read();read();read();R[1]=read();
	son[1].push_back(1);anc[1].push_back(1);vis[1]=true;
	d[1].push_back(0);ToMe[1].ins(-R[1]);puts("0");
	rep(2,n,i)
	{
		int f=read()^(ans%M),w=read(),r=R[i]=read();
		ins(f,i,w);anc[i]=anc[f];vis[i]=true;
		anc[i].push_back(i);son[i].push_back(i);
		for(unsigned j=0;j<anc[f].size();++j)
		{
			int u=anc[f][j];d[i].push_back(d[f][j]+w);son[u].push_back(i);
			ans+=ToMe[u].qry(r-d[i][j]);ToMe[u].ins(d[i][j]-r);
			if(j)ans-=ToFa[u].qry(r-d[i][j-1]),ToFa[u].ins(d[i][j-1]-r);
		}
//		printf("%d :: %d %d\n",i,int(d[i].size()),f);
		
		d[i].push_back(0);ToMe[i].ins(-r);ToFa[i].ins(w-r);
		for(unsigned j=1;j<anc[i].size();++j)
		{
			if(1.*son[anc[i][j]].size()>son[anc[i][j-1]].size()*alpha)
			{
				int u=anc[i][j-1];
				for(int v:son[u])
				{
					ToMe[v].clear();
					ToFa[v].clear();
					while(*prev(anc[v].end())!=u)
					{
						anc[v].pop_back();
						d[v].pop_back();
					}
					anc[v].pop_back();
					d[v].pop_back();
					vis[v]=false;
				}
				Sz=son[u].size();Mn=M;getRt(u);
//				printf("Have Been Rebuild (%d)%d\n",u,Rt);
				
				build(Rt);break;
			}
		}
		
		
		printf("%lld\n",ans);
	}
}
